type Cell = [number, number]; // [x, y]

const toKey = ([x, y]: Cell): string => `${x},${y}`;

function neighborsOf([x, y]: Cell): Cell[] {
  const neighbors: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      neighbors.push([x + dx, y + dy]);
    }
  }
  return neighbors;
}

function countLiveNeighbors(cell: Cell, living: Set<string>): number {
  return neighborsOf(cell).filter((n) => living.has(toKey(n))).length;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const living = new Set(cells.map(toKey));

  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    candidates.set(toKey(cell), cell);
    for (const n of neighborsOf(cell)) candidates.set(toKey(n), n);
  }

  const next: Cell[] = [];
  for (const cell of candidates.values()) {
    const neighbors = countLiveNeighbors(cell, living);
    const isAlive = living.has(toKey(cell));
    if (isAlive ? neighbors === 2 || neighbors === 3 : neighbors === 3) {
      next.push(cell);
    }
  }
  return next;
}

